  1→import { Component, HostBinding, inject, OnInit } from '@angular/core';
  2→import { MatDialog } from '@angular/material/dialog';
  3→import { MatSnackBar } from '@angular/material/snack-bar';
  4→import { Router, RouterOutlet } from '@angular/router';
  5→import { Actions, ofType } from '@ngrx/effects';
  6→import { Store } from '@ngrx/store';
  7→import { TranslateService } from '@ngx-translate/core';
  8→import { EpgService } from '@iptvnator/epg/data-access';
  9→import { EpgProgressPanelComponent } from '@iptvnator/ui/epg';
 10→import { PlaylistActions, selectAllPlaylistsMeta } from 'm3u-state';
 11→import { filter, take } from 'rxjs';
 12→import { DataService } from 'services';
 13→import {
 14→    AUTO_UPDATE_PLAYLISTS,
 15→    Language,
 16→    OPEN_FILE,
 17→    Settings,
 18→    STORE_KEY,
 19→    Theme,
 20→} from 'shared-interfaces';
 21→import { SettingsService } from './services/settings.service';
 22→
 23→@Component({
 24→    selector: 'app-root',
 25→    templateUrl: './app.component.html',
 26→    imports: [EpgProgressPanelComponent, RouterOutlet],
 27→})
 28→export class AppComponent implements OnInit {
 29→    @HostBinding('class.macos-platform') get isMacOS() {
 30→        return (
 31→            window.electron && navigator.platform.toLowerCase().includes('mac')
 32→        );
 33→    }
 34→    private actions$ = inject(Actions);
 35→    private dataService = inject(DataService);
 36→    private dialog = inject(MatDialog);
 37→    private epgService = inject(EpgService);
 38→    private snackBar = inject(MatSnackBar);
 39→    private router = inject(Router);
 40→    private store = inject(Store);
 41→    private translate = inject(TranslateService);
 42→    private settingsService = inject(SettingsService);
 43→
 44→    /** Default language as fallback */
 45→    private readonly DEFAULT_LANG = Language.ENGLISH;
 46→
 47→    constructor() {
 48→        if (
 49→            ((this.dataService.isElectron &&
 50→                this.dataService?.remote?.process.platform === 'linux') ||
 51→                this.dataService?.remote?.process.platform === 'win32') &&
 52→            this.dataService.remote.process.argv.length > 2
 53→        ) {
 54→            const filePath = this.dataService.remote.process.argv.find(
 55→                (filepath) =>
 56→                    filepath.endsWith('.m3u') || filepath.endsWith('.m3u8')
 57→            );
 58→            if (filePath) {
 59→                const filePathsArray = filePath.split('/');
 60→                const fileName = filePathsArray[filePathsArray.length - 1];
 61→                this.dataService.sendIpcEvent(OPEN_FILE, {
 62→                    filePath,
 63→                    fileName,
 64→                });
 65→            }
 66→        }
 67→        if (window.electron) {
 68→            document.addEventListener('keydown', (event) => {
 69→                if (event.ctrlKey || event.metaKey) {
 70→                    if (event.key === 'f') {
 71→                        event.preventDefault();
 72→                        this.openGlobalSearch();
 73→                    } else if (event.key === 'r') {
 74→                        event.preventDefault();
 75→                        this.openGlobalRecent();
 76→                    }
 77→                }
 78→            });
 79→        }
 80→    }
 81→
 82→    ngOnInit() {
 83→        this.store.dispatch(PlaylistActions.loadPlaylists());
 84→        this.translate.setDefaultLang(this.DEFAULT_LANG);
 85→
 86→        this.initSettings();
 87→        this.triggerAutoUpdatePlaylists();
 88→    }
 89→
 90→    /**
 91→     * Reads the settings object from local storage and initializes the
 92→     * application based on them
 93→     */
 94→    initSettings(): void {
 95→        this.settingsService
 96→            .getValueFromLocalStorage(STORE_KEY.Settings)
 97→            .subscribe((settings: Settings) => {
 98→                if (settings && Object.keys(settings).length > 0) {
 99→                    // No need to send settings to Electron on init
100→                    // Settings are stored in IndexedDB and loaded by the settings store
101→                    // Only specific Electron settings (MPV/VLC paths) are sent when changed in settings component
102→
103→                    this.translate.use(settings.language ?? this.DEFAULT_LANG);
104→
105→                    // Fetch EPG if URLs are configured (only fetch stale data)
106→                    if (
107→                        window.electron &&
108→                        settings.epgUrl?.length > 0 &&
109→                        settings.epgUrl?.some((u) => u !== '')
110→                    ) {
111→                        this.fetchStaleEpgData(settings.epgUrl);
112→                    }
113→
114→                    if (settings.theme) {
115→                        this.settingsService.changeTheme(settings.theme);
116→                    } else {
117→                        this.detectDarkMode();
118→                    }
119→                } else {
120→                    this.detectDarkMode();
121→                }
122→            });
123→    }
124→
125→    /**
126→     * Applies the operating system color scheme when no explicit theme is set
127→     */
128→    detectDarkMode(): void {
129→        this.settingsService.changeTheme(Theme.SystemTheme);
130→    }
131→
132→    /**
133→     * Navigate to the specified route
134→     * @param route route to navigate to
135→     */
136→    navigateToRoute(route: string) {
137→        this.router.navigateByUrl(route);
138→    }
139→
140→    openGlobalSearch(initialQuery = ''): void {
141→        void import('@iptvnator/portal/xtream/feature').then(
142→            ({ GlobalSearchResultsComponent }) => {
143→                this.dialog.open(GlobalSearchResultsComponent, {
144→                    width: '100%',
145→                    height: '100%',
146→                    maxWidth: '100%',
147→                    panelClass: 'global-search-overlay',
148→                    data: { isGlobalSearch: true, initialQuery },
149→                });
150→            }
151→        );
152→    }
153→
154→    openGlobalRecent(): void {
155→        void import('@iptvnator/portal/xtream/feature').then(
156→            ({ GlobalRecentlyViewedComponent }) => {
157→                this.dialog.open(GlobalRecentlyViewedComponent, {
158→                    width: '100%',
159→                    height: '100%',
160→                    maxWidth: '100%',
161→                    panelClass: 'global-search-overlay',
162→                    data: { isGlobal: true },
163→                    hasBackdrop: true,
164→                    disableClose: false,
165→                });
166→            }
167→        );
168→    }
169→
170→    /**
171→     * Fetches EPG data only for URLs that have stale or missing data.
172→     * Data is considered fresh if updated within the last 12 hours.
173→     */
174→    private async fetchStaleEpgData(urls: string[]): Promise<void> {
175→        try {
176→            const result = await window.electron.checkEpgFreshness(urls, 12);
177→
178→            if (result.freshUrls.length > 0) {
179→                console.log(
180→                    `EPG: ${result.freshUrls.length} source(s) already fresh, skipping fetch`
181→                );
182→                // Show snackbar if all EPG sources are fresh (no stale URLs)
183→                if (result.staleUrls.length === 0) {
184→                    this.snackBar.open(
185→                        this.translate.instant('EPG.UP_TO_DATE'),
186→                        this.translate.instant('CLOSE'),
187→                        { duration: 3000 }
188→                    );
189→                }
190→            }
191→
192→            if (result.staleUrls.length > 0) {
193→                console.log(
194→                    `EPG: Fetching ${result.staleUrls.length} stale source(s)`
195→                );
196→                this.epgService.fetchEpg(result.staleUrls);
197→            }
198→        } catch (error) {
199→            console.error('Error checking EPG freshness, fetching all:', error);
200→            // Fallback: fetch all URLs if freshness check fails
201→            this.epgService.fetchEpg(urls);
202→        }
203→    }
204→
205→    /**
206→     * Triggers auto-update for playlists that have autoRefresh enabled
207→     */
208→    private triggerAutoUpdatePlaylists(): void {
209→        // Wait for playlists to be loaded successfully
210→        this.actions$
211→            .pipe(
212→                ofType(PlaylistActions.loadPlaylistsSuccess),
213→                take(1) // Only trigger once on app startup
214→            )
215→            .subscribe(() => {
216→                // Get all playlists from store
217→                this.store
218→                    .select(selectAllPlaylistsMeta)
219→                    .pipe(
220→                        take(1),
221→                        filter((playlists) => playlists.length > 0)
222→                    )
223→                    .subscribe((playlists) => {
224→                        // Filter playlists with autoRefresh enabled
225→                        const playlistsToUpdate = playlists.filter(
226→                            (playlist) => playlist.autoRefresh === true
227→                        );
228→
229→                        // Trigger auto-update if there are playlists to update
230→                        if (playlistsToUpdate.length > 0) {
231→                            console.log(
232→                                `Auto-updating ${playlistsToUpdate.length} playlist(s) on startup`
233→                            );
234→                            this.dataService.sendIpcEvent(
235→                                AUTO_UPDATE_PLAYLISTS,
236→                                playlistsToUpdate
237→                            );
238→                        }
239→                    });
240→            });
241→    }
242→}
