 1→import { inject, Injectable, Provider } from '@angular/core';
 2→import { MatDialog } from '@angular/material/dialog';
 3→import { PlaylistType } from '@iptvnator/playlist/shared/ui';
 4→import {
 5→    WORKSPACE_SHELL_ACTIONS,
 6→    WorkspaceAccountInfoData,
 7→    WorkspaceShellActions,
 8→} from '@iptvnator/workspace/shell/util';
 9→
10→@Injectable({ providedIn: 'root' })
11→export class AppWorkspaceShellActionsService implements WorkspaceShellActions {
12→    private readonly dialog = inject(MatDialog);
13→
14→    openAddPlaylistDialog(type: PlaylistType): void {
15→        void import('@iptvnator/playlist/import/feature').then(
16→            ({ AddPlaylistDialogComponent }) => {
17→                this.dialog.open(AddPlaylistDialogComponent, {
18→                    width: '600px',
19→                    data: { type },
20→                });
21→            }
22→        );
23→    }
24→
25→    openGlobalSearch(initialQuery = ''): void {
26→        void import('@iptvnator/portal/xtream/feature').then(
27→            ({ GlobalSearchResultsComponent }) => {
28→                this.dialog.open(GlobalSearchResultsComponent, {
29→                    width: '100%',
30→                    height: '100%',
31→                    maxWidth: '100%',
32→                    panelClass: 'global-search-overlay',
33→                    data: {
34→                        isGlobalSearch: true,
35→                        initialQuery,
36→                    },
37→                });
38→            }
39→        );
40→    }
41→
42→    openGlobalRecent(): void {
43→        void import('@iptvnator/portal/xtream/feature').then(
44→            ({ GlobalRecentlyViewedComponent }) => {
45→                this.dialog.open(GlobalRecentlyViewedComponent, {
46→                    width: '100%',
47→                    height: '100%',
48→                    maxWidth: '100%',
49→                    panelClass: 'global-search-overlay',
50→                    data: { isGlobal: true },
51→                    hasBackdrop: true,
52→                    disableClose: false,
53→                });
54→            }
55→        );
56→    }
57→
58→    openAccountInfo(data: WorkspaceAccountInfoData): void {
59→        void import('@iptvnator/portal/xtream/feature').then(
60→            ({ AccountInfoComponent }) => {
61→                this.dialog.open(AccountInfoComponent, {
62→                    width: '80%',
63→                    maxWidth: '1200px',
64→                    maxHeight: '90vh',
65→                    data,
66→                });
67→            }
68→        );
69→    }
70→}
71→
72→export function provideWorkspaceShellActions(): Provider[] {
73→    return [
74→        AppWorkspaceShellActionsService,
75→        {
76→            provide: WORKSPACE_SHELL_ACTIONS,
77→            useExisting: AppWorkspaceShellActionsService,
78→        },
79→    ];
80→}
