 1→import { InjectionToken } from '@angular/core';
 2→
 3→export type WorkspacePlaylistType = 'xtream' | 'url' | 'text' | 'file' | 'stalker';
 4→
 5→export interface WorkspaceAccountInfoData {
 6→    vodStreamsCount: number;
 7→    liveStreamsCount: number;
 8→    seriesCount: number;
 9→}
10→
11→export interface WorkspaceShellActions {
12→    openAddPlaylistDialog(type: WorkspacePlaylistType): void;
13→    openGlobalSearch(initialQuery?: string): void;
14→    openGlobalRecent(): void;
15→    openAccountInfo(data: WorkspaceAccountInfoData): void;
16→}
17→
18→export const WORKSPACE_SHELL_ACTIONS =
19→    new InjectionToken<WorkspaceShellActions>('WORKSPACE_SHELL_ACTIONS');
