  1→import {
  2→    CdkDragDrop,
  3→    DragDropModule,
  4→    moveItemInArray,
  5→} from '@angular/cdk/drag-drop';
  6→import { Component, computed, inject, signal } from '@angular/core';
  7→import { toSignal } from '@angular/core/rxjs-interop';
  8→import { MatButtonModule } from '@angular/material/button';
  9→import { MatCheckboxModule } from '@angular/material/checkbox';
 10→import { MatChipsModule } from '@angular/material/chips';
 11→import { MatExpansionModule } from '@angular/material/expansion';
 12→import { MatIcon } from '@angular/material/icon';
 13→import { MatSlideToggleModule } from '@angular/material/slide-toggle';
 14→import { MatTooltip } from '@angular/material/tooltip';
 15→import { Store } from '@ngrx/store';
 16→import { TranslatePipe, TranslateService } from '@ngx-translate/core';
 17→import { selectAllPlaylistsMeta } from 'm3u-state';
 18→import { startWith } from 'rxjs';
 19→import {
 20→    DashboardLayoutService,
 21→    DashboardWidgetConfig,
 22→    DashboardWidgetProvider,
 23→    DashboardWidgetSize,
 24→    createDefaultWidgetScope,
 25→} from 'workspace-dashboard-data-access';
 26→import { DashboardWidgetHostComponent } from 'workspace-dashboard-ui';
 27→
 28→@Component({
 29→    selector: 'app-workspace-dashboard',
 30→    imports: [
 31→        DashboardWidgetHostComponent,
 32→        DragDropModule,
 33→        MatButtonModule,
 34→        MatCheckboxModule,
 35→        MatChipsModule,
 36→        MatExpansionModule,
 37→        MatIcon,
 38→        MatSlideToggleModule,
 39→        MatTooltip,
 40→        TranslatePipe,
 41→    ],
 42→    templateUrl: './workspace-dashboard.component.html',
 43→    styleUrl: './workspace-dashboard.component.scss',
 44→})
 45→export class WorkspaceDashboardComponent {
 46→    private readonly store = inject(Store);
 47→    private readonly translate = inject(TranslateService);
 48→
 49→    readonly editMode = signal(false);
 50→    readonly playlists = this.store.selectSignal(selectAllPlaylistsMeta);
 51→    private readonly languageTick = toSignal(
 52→        this.translate.onLangChange.pipe(startWith(null)),
 53→        { initialValue: null }
 54→    );
 55→    readonly providerOptions: DashboardWidgetProvider[] = [
 56→        'm3u',
 57→        'xtream',
 58→        'stalker',
 59→    ];
 60→    private readonly sizeOrder: DashboardWidgetSize[] = [
 61→        'one-third',
 62→        'half',
 63→        'two-thirds',
 64→        'full',
 65→    ];
 66→
 67→    readonly allWidgets = computed(() =>
 68→        [...this.layoutService.state().widgets].sort(
 69→            (a, b) => a.order - b.order
 70→        )
 71→    );
 72→    readonly visibleWidgets = computed(() =>
 73→        this.allWidgets().filter((widget) => widget.enabled)
 74→    );
 75→
 76→    constructor(readonly layoutService: DashboardLayoutService) {
 77→        // Data reload is handled reactively by DashboardDataService
 78→        // via Router NavigationEnd events
 79→    }
 80→
 81→    toggleEditMode(): void {
 82→        this.editMode.update((value) => !value);
 83→    }
 84→
 85→    onWidgetDrop(event: CdkDragDrop<DashboardWidgetConfig[]>): void {
 86→        if (event.previousIndex === event.currentIndex) {
 87→            return;
 88→        }
 89→        const reordered = [...this.visibleWidgets()];
 90→        moveItemInArray(reordered, event.previousIndex, event.currentIndex);
 91→        this.layoutService.reorderVisibleWidgets(
 92→            reordered.map((widget) => widget.id)
 93→        );
 94→    }
 95→
 96→    setWidgetSize(widgetId: string, size: unknown): void {
