107→    cycleWidgetSize(widgetId: string, dir: 1 | -1): void {
108→        const widget = this.allWidgets().find((w) => w.id === widgetId);
109→        if (!widget) return;
110→        const idx = this.sizeOrder.indexOf(widget.size);
111→        const next = this.sizeOrder[idx + dir];
112→        if (next) this.layoutService.setWidgetSize(widgetId, next);
