284→    private updateActivePlaylistFromRoute(url: string) {
285→        // Match routes like /playlists/:id, /xtreams/:id, /stalker/:id
286→        const match = url.match(/\/(playlists|xtreams|stalker)\/([^/?]+)/);
287→        if (match) {
288→            this.routePlaylistId.set(match[2]);
289→        } else {
290→            this.routePlaylistId.set(null);
291→        }
292→    }
