294→    private rememberSectionFromRoute(url: string): void {
295→        const routeContext = this.getRouteContext(url);
296→        if (!routeContext.provider || !routeContext.section) {
297→            return;
298→        }
299→
300→        const normalized = this.normalizeSectionForProvider(
301→            routeContext.section,
302→            routeContext.provider
303→        );
304→        if (!normalized) {
305→            return;
306→        }
307→
308→        const memory = this.readSectionMemory();
309→        memory.providers[routeContext.provider] = normalized;
310→        if (routeContext.playlistId) {
311→            memory.playlists[routeContext.playlistId] = {
312→                provider: routeContext.provider,
313→                section: normalized,
314→                updatedAt: Date.now(),
315→            };
316→        }
317→        this.writeSectionMemory(memory);
318→    }
