399→        );
400→    }
401→
402→    private focusSearchField() {
403→        this.clearSearchFocusTimeout();
404→        this.focusSearchTimeoutId = setTimeout(() => {
405→            const input = this.searchInput()?.nativeElement;
406→            if (!input) {
407→                return;
408→            }
409→            input.focus();
410→            input.select();
411→            this.focusSearchTimeoutId = null;
412→        }, 0);
413→    }
414→
415→    private clearSearchFocusTimeout() {
416→        if (this.focusSearchTimeoutId !== null) {
417→            clearTimeout(this.focusSearchTimeoutId);
418→            this.focusSearchTimeoutId = null;
419→        }
420→    }
421→
422→    selectPlaylist(playlist: PlaylistMeta) {
423→        const routeContext = this.getRouteContext(this.router.url);
424→        const provider = this.getProviderForPlaylist(playlist);
425→
426→        this.setActivePlaylist(playlist._id);
427→
428→        const targetCommands = this.getTargetCommands(
429→            provider,
430→            playlist._id,
431→            routeContext
432→        );
433→        if (targetCommands) {
434→            this.router.navigate(targetCommands);
435→        }
436→
437→        this.playlistSelected.emit(playlist._id);
438→    }
439→
440→    private setActivePlaylist(playlistId: string): void {
441→        this.store.dispatch(PlaylistActions.setActivePlaylist({ playlistId }));
442→    }
443→
444→    private isWorkspaceRoute(url: string): boolean {
445→        return /^\/workspace(?:\/|$)/.test(url);
446→    }
447→
448→    private getProviderForPlaylist(
449→        playlist: PlaylistMeta
450→    ): PlaylistRouteProvider {
451→        if (playlist.serverUrl) {
452→            return 'xtreams';
453→        }
454→        if (playlist.macAddress) {
455→            return 'stalker';
456→        }
457→        return 'playlists';
458→    }
459→
460→    private getPlaylistFilterType(playlist: PlaylistMeta): PlaylistFilterType {
461→        if (playlist.macAddress) {
462→            return 'stalker';
463→        }
464→        if (playlist.serverUrl) {
465→            return 'xtream';
466→        }
467→        return 'm3u';
468→    }
469→
470→    private getRouteContext(url: string): PlaylistRouteContext {
471→        const inWorkspace = this.isWorkspaceRoute(url);
472→        const isWorkspaceDashboard =
473→            /^\/workspace(?:\/dashboard)?(?:\/)?(?:\?.*)?$/.test(url);
474→        const match = url.match(
475→            /^\/(?:workspace\/)?(playlists|xtreams|stalker)\/([^/?]+)(?:\/([^/?]+))?/
476→        );
477→
478→        return {
479→            inWorkspace,
480→            isWorkspaceDashboard,
481→            provider: (match?.[1] as PlaylistRouteProvider | undefined) ?? null,
482→            playlistId: match?.[2] ?? null,
483→            section: match?.[3] ?? null,
484→        };
485→    }
486→
487→    private getTargetCommands(
488→        provider: PlaylistRouteProvider,
489→        playlistId: string,
490→        routeContext: PlaylistRouteContext
491→    ): string[] | null {
492→        const prefix = routeContext.inWorkspace ? ['workspace'] : [];
493→
494→        // In workspace routes without explicit provider context (for example
495→        // dashboard and sources), selecting a source should only change active
496→        // context and must not trigger navigation.
497→        if (routeContext.inWorkspace && !routeContext.provider) {
498→            return null;
499→        }
500→
501→        if (provider === 'playlists') {
502→            const section = this.resolveTargetSection(
503→                provider,
504→                routeContext.section,
505→                playlistId
506→            );
507→            return [...prefix, 'playlists', playlistId, section];
508→        }
509→
510→        if (!this.supportsSectionNavigation(provider)) {
511→            return [...prefix, provider, playlistId];
512→        }
513→
514→        const section = this.resolveTargetSection(
515→            provider,
516→            routeContext.section,
517→            playlistId
518→        );
519→        return [...prefix, provider, playlistId, section];
520→    }
521→
522→    private resolveTargetSection(
523→        provider: PlaylistSectionProvider,
524→        currentSection: string | null,
525→        targetPlaylistId: string
526→    ): string {
527→        const fromCurrent = this.normalizeSectionForProvider(
528→            currentSection,
529→            provider
530→        );
531→        if (fromCurrent) {
532→            return fromCurrent;
533→        }
534→
535→        const memory = this.readSectionMemory();
536→        const playlistMemory = memory.playlists[targetPlaylistId];
537→        if (playlistMemory?.provider === provider) {
538→            const normalizedPlaylistSection = this.normalizeSectionForProvider(
539→                playlistMemory.section,
540→                provider
541→            );
542→            if (normalizedPlaylistSection) {
543→                return normalizedPlaylistSection;
544→            }
545→        }
546→
547→        const providerMemory = memory.providers[provider];
548→        const normalizedProviderSection = this.normalizeSectionForProvider(
549→            providerMemory,
550→            provider
551→        );
552→        if (normalizedProviderSection) {
553→            return normalizedProviderSection;
554→        }
555→
556→        if (provider === 'playlists') {
557→            return 'all';
558→        }
559→
560→        return 'vod';
561→    }
562→
563→    private supportsSectionNavigation(
564→        provider: PlaylistSectionProvider
565→    ): boolean {
566→        if (provider === 'xtreams') {
567→            return Boolean(window.electron);
568→        }
569→        return true;
570→    }
571→
572→    private normalizeSectionForProvider(
573→        section: string | null | undefined,
574→        provider: PlaylistSectionProvider
575→    ): string | null {
576→        if (!section) {
577→            return null;
578→        }
579→
580→        if (provider === 'xtreams') {
581→            if (section === 'itv') {
582→                return 'live';
583→            }
584→            return XTREAM_SECTIONS.includes(
585→                section as (typeof XTREAM_SECTIONS)[number]
586→            )
587→                ? section
588→                : null;
589→        }
590→
591→        if (provider === 'playlists') {
592→            return M3U_SECTIONS.includes(
593→                section as (typeof M3U_SECTIONS)[number]
594→            )
595→                ? section
596→                : null;
597→        }
598→
599→        if (section === 'live') {
600→            return 'itv';
601→        }
602→        if (section === 'recently-added') {
603→            return 'recent';
604→        }
605→        return STALKER_SECTIONS.includes(
606→            section as (typeof STALKER_SECTIONS)[number]
607→        )
608→            ? section
609→            : null;
610→    }
611→
612→    private readSectionMemory(): PlaylistSectionMemory {
613→        const empty: PlaylistSectionMemory = { providers: {}, playlists: {} };
614→
615→        try {
616→            const raw = localStorage.getItem(LAST_SECTION_STORAGE_KEY);
617→            if (!raw) {
618→                return empty;
619→            }
620→            const parsed = JSON.parse(raw);
621→            if (typeof parsed !== 'object' || parsed === null) {
622→                return empty;
623→            }
624→
625→            const providers: Partial<Record<PlaylistSectionProvider, string>> =
626→                {};
627→            const playlists: PlaylistSectionMemory['playlists'] = {};
628→
629→            const parsedProviders = (parsed as Record<string, unknown>)[
630→                'providers'
631→            ];
632→            if (
633→                typeof parsedProviders === 'object' &&
634→                parsedProviders !== null
635→            ) {
636→                const candidate = parsedProviders as Record<string, unknown>;
637→                if (typeof candidate['playlists'] === 'string') {
638→                    providers.playlists = candidate['playlists'];
639→                }
640→                if (typeof candidate['xtreams'] === 'string') {
641→                    providers.xtreams = candidate['xtreams'];
642→                }
643→                if (typeof candidate['stalker'] === 'string') {
644→                    providers.stalker = candidate['stalker'];
645→                }
646→            } else {
647→                // Backward compatibility with previous format:
648→                // { playlists: "...", xtreams: "...", stalker: "..." }
649→                const legacy = parsed as Record<string, unknown>;
650→                if (typeof legacy['playlists'] === 'string') {
651→                    providers.playlists = legacy['playlists'];
652→                }
653→                if (typeof legacy['xtreams'] === 'string') {
654→                    providers.xtreams = legacy['xtreams'];
655→                }
656→                if (typeof legacy['stalker'] === 'string') {
657→                    providers.stalker = legacy['stalker'];
658→                }
659→            }
660→
661→            const parsedPlaylists = (parsed as Record<string, unknown>)[
662→                'playlists'
663→            ];
664→            if (
665→                typeof parsedPlaylists === 'object' &&
666→                parsedPlaylists !== null
667→            ) {
668→                Object.entries(
669→                    parsedPlaylists as Record<string, unknown>
670→                ).forEach(([playlistId, value]) => {
671→                    if (!value || typeof value !== 'object' || !playlistId) {
672→                        return;
673→                    }
674→
675→                    const row = value as Record<string, unknown>;
676→                    const provider = row['provider'];
677→                    const section = row['section'];
678→                    const updatedAt = row['updatedAt'];
679→                    const isProviderValid =
680→                        provider === 'playlists' ||
681→                        provider === 'xtreams' ||
682→                        provider === 'stalker';
683→                    if (!isProviderValid || typeof section !== 'string') {
684→                        return;
685→                    }
686→
687→                    playlists[playlistId] = {
688→                        provider,
689→                        section,
690→                        updatedAt:
691→                            typeof updatedAt === 'number'
692→                                ? updatedAt
693→                                : Date.now(),
694→                    };
695→                });
696→            }
697→
698→            return { providers, playlists };
699→        } catch {
700→            return empty;
701→        }
702→    }
703→
704→    private writeSectionMemory(memory: PlaylistSectionMemory): void {
705→        try {
706→            localStorage.setItem(
707→                LAST_SECTION_STORAGE_KEY,
708→                JSON.stringify(memory)
709→            );
710→        } catch {
711→            // Ignore storage write failures (private mode/storage quota).
712→        }
713→    }
714→
715→    private readPersistedActivePlaylistId(): string | null {
716→        try {
717→            const value = localStorage.getItem(
718→                LAST_ACTIVE_PLAYLIST_STORAGE_KEY
719→            );
720→            return value && value.trim().length > 0 ? value : null;
721→        } catch {
722→            return null;
723→        }
724→    }
725→
726→    private writePersistedActivePlaylistId(playlistId: string): void {
727→        try {
728→            localStorage.setItem(LAST_ACTIVE_PLAYLIST_STORAGE_KEY, playlistId);
729→        } catch {
730→            // Ignore storage write failures (private mode/storage quota).
731→        }
732→    }
733→
734→    private clearPersistedActivePlaylistId(): void {
735→        try {
736→            localStorage.removeItem(LAST_ACTIVE_PLAYLIST_STORAGE_KEY);
737→        } catch {
738→            // Ignore storage write failures.
739→        }
740→    }
741→
742→    private readPersistedSearchQuery(): string {
743→        try {
744→            return localStorage.getItem(SEARCH_QUERY_STORAGE_KEY) ?? '';
745→        } catch {
746→            return '';
747→        }
748→    }
749→
750→    private writePersistedSearchQuery(value: string): void {
751→        try {
752→            localStorage.setItem(SEARCH_QUERY_STORAGE_KEY, value);
753→        } catch {
754→            // Ignore storage write failures (private mode/storage quota).
755→        }
756→    }
757→
758→    private readPersistedTypeFilters(): Record<PlaylistFilterType, boolean> {
759→        try {
760→            const raw = localStorage.getItem(PLAYLIST_TYPE_FILTER_STORAGE_KEY);
761→            if (!raw) {
762→                return { ...DEFAULT_PLAYLIST_TYPE_FILTERS };
763→            }
764→
765→            const parsed = JSON.parse(raw) as Partial<
766→                Record<PlaylistFilterType, boolean>
767→            >;
768→            const next = {
769→                m3u: parsed.m3u !== false,
770→                stalker: parsed.stalker !== false,
771→                xtream: parsed.xtream !== false,
772→            };
773→
774→            if (!next.m3u && !next.stalker && !next.xtream) {
775→                return { ...DEFAULT_PLAYLIST_TYPE_FILTERS };
776→            }
777→
778→            return next;
779→        } catch {
780→            return { ...DEFAULT_PLAYLIST_TYPE_FILTERS };
781→        }
782→    }
783→
784→    private writePersistedTypeFilters(
785→        filters: Record<PlaylistFilterType, boolean>
786→    ): void {
787→        try {
788→            localStorage.setItem(
789→                PLAYLIST_TYPE_FILTER_STORAGE_KEY,
790→                JSON.stringify(filters)
791→            );
792→        } catch {
793→            // Ignore storage write failures (private mode/storage quota).
794→        }
795→    }
796→
797→    private removeDeletedPlaylistsFromSectionMemory(
798→        existingIds: string[]
799→    ): void {
800→        const existingIdSet = new Set(existingIds);
801→        const memory = this.readSectionMemory();
802→        const currentEntries = Object.entries(memory.playlists);
803→        if (currentEntries.length === 0) {
804→            return;
805→        }
806→
807→        const nextPlaylists: PlaylistSectionMemory['playlists'] = {};
808→        let hasChanges = false;
809→
810→        currentEntries.forEach(([playlistId, entry]) => {
811→            if (!existingIdSet.has(playlistId)) {
812→                hasChanges = true;
813→                return;
814→            }
815→
816→            const normalizedSection = this.normalizeSectionForProvider(
817→                entry.section,
818→                entry.provider
819→            );
820→            if (!normalizedSection) {
821→                hasChanges = true;
822→                return;
823→            }
824→
825→            nextPlaylists[playlistId] = {
826→                ...entry,
827→                section: normalizedSection,
828→            };
829→        });
830→
831→        if (!hasChanges) {
832→            return;
833→        }
834→
835→        this.writeSectionMemory({
836→            providers: memory.providers,
837→            playlists: nextPlaylists,
838→        });
839→    }
840→
841→    getPlaylistIcon(playlist: PlaylistMeta): string {
842→        if (playlist.macAddress) {
843→            return 'dashboard';
844→        }
845→        if (playlist.serverUrl) {
846→            return 'public';
847→        }
848→        if (playlist.url) {
849→            return 'cloud';
850→        }
851→        return 'folder';
852→    }
853→
854→    getPlaylistTypeLabel(playlist: PlaylistMeta): string {
855→        if (playlist.macAddress) {
856→            return 'Stalker Portal';
857→        }
858→        if (playlist.serverUrl) {
859→            return 'Xtream Code';
860→        }
861→        return `${playlist.count} channels`;
862→    }
863→
864→    getStatusClass(playlistId: string): string {
865→        const status = this.portalStatuses().get(playlistId);
866→        return this.portalStatusService.getStatusClass(status || 'unavailable');
867→    }
868→
869→    isSelected(playlist: PlaylistMeta): boolean {
870→        return this.activePlaylistId() === playlist._id;
871→    }
872→}
