            {
                icon: 'search',
                tooltip: 'Search (this playlist)',
                path: [...root, 'search'],
                section: 'search',
            },
            {
                icon: 'history',
                tooltip: 'Recently viewed (this playlist)',
                path: [...root, 'recent'],
                section: 'recent',
            },
            {
                icon: 'favorite',
                tooltip: 'Favorites (this playlist)',
                path: [...root, 'favorites'],
                section: 'favorites',
            },
        ];

        if (isElectron) {
            secondary.push({
                icon: 'download',
                tooltip: 'Downloads (this playlist)',
                path: [...root, 'downloads'],
                section: 'downloads',
            });
        }

        return { primary, secondary };
    }

    if (provider === 'playlists') {
        const primary: PortalRailLink[] = [
            {
                icon: 'tv',
                tooltip: 'All channels (this playlist)',
                path: [...root, 'all'],
                exact: true,
                section: 'all',
            },
            {
                icon: 'folder',
                tooltip: 'Groups (this playlist)',
                path: [...root, 'groups'],
                exact: true,
                section: 'groups',
            },
            {
                icon: 'history',
                tooltip: 'Recently viewed (this playlist)',
                path: [...root, 'recent'],
                exact: true,
                section: 'recent',
            },
            {
                icon: 'star',
                tooltip: 'Favorites (this playlist)',
                path: [...root, 'favorites'],
                exact: true,
                section: 'favorites',
            },
        ];

        return {
            primary,
            secondary: [],
        };
    }

    return { primary: [], secondary: [] };
}

