        /^\/workspace(?:\/dashboard)?(?:\/)?(?:\?.*)?$/.test(this.currentUrl())
    );
    readonly isSourcesRoute = computed(() =>
        /^\/workspace\/sources(?:\/)?(?:\?.*)?$/.test(this.currentUrl())
    );
