    background: var(--app-header-bg, var(--mat-sys-surface-container-low));
    app-region: drag;
}

.playlist-switcher {
    width: min(260px, 32vw);
    flex-shrink: 0;
    app-region: no-drag;
}

.settings-header-title {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: var(--mat-sys-on-surface);
    app-region: no-drag;
}

// ─── Search Field ─────────────────────────────────────────────────────────────
.search-field {
    flex: 1;
    min-width: 160px;
    height: 36px;
    border-radius: 10px;
    border: 1px solid var(--app-search-border, var(--mat-sys-outline-variant));
    background: var(--app-search-bg, var(--mat-sys-surface-container));
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 0 12px;
    transition:
        border-color 0.15s ease,
        background-color 0.15s ease,
        box-shadow 0.15s ease;
    app-region: no-drag;

    &:focus-within {
        border-color: var(--mat-sys-primary);
        box-shadow: 0 0 0 3px color-mix(in srgb, var(--mat-sys-primary) 12%, transparent);
    }

    mat-icon {
        font-size: 18px;
        width: 18px;
        height: 18px;
        color: var(--mat-sys-on-surface-variant);
        flex-shrink: 0;
    }

    input {
        flex: 1;
        border: none;
        outline: none;
        background: transparent;
        color: var(--mat-sys-on-surface);
        font: inherit;
        font-size: 0.875rem;

        &:disabled {
            cursor: not-allowed;
            opacity: 0.5;
        }

        &::placeholder {
            color: var(--mat-sys-on-surface-variant);
            opacity: 0.7;
        }
    }

    .command-trigger {
        width: 28px;
        height: 28px;
        padding: 0;
        margin-right: -4px;
        color: var(--mat-sys-on-surface-variant);
        border-radius: 8px;
        flex-shrink: 0;

        &:hover {
            background: var(--mat-sys-surface-container-high);
            color: var(--mat-sys-on-surface);
        }

        mat-icon {
            font-size: 16px;
            width: 16px;
            height: 16px;
        }
    }
}

// ─── Header Actions ───────────────────────────────────────────────────────────
.header-actions {
    display: flex;
    align-items: center;
    gap: 4px;
    app-region: no-drag;

    button,
    a {
        color: var(--mat-sys-on-surface-variant);
        border-radius: 8px;
        transition:
            color 0.15s ease,
            background 0.15s ease;

        &:hover {
            color: var(--mat-sys-on-surface);
            background: var(--mat-sys-surface-container);
        }

        &.is-active {
            color: var(--app-selection-color);
            background: linear-gradient(
                145deg,
                var(--app-selection-surface-strong),
                var(--app-selection-surface)
            );
            box-shadow:
                inset 0 0 0 1px var(--app-selection-border),
                0 10px 20px -16px var(--app-selection-glow);
        }
    }
}

.header-actions-divider {
    width: 1px;
    height: 20px;
    background: var(--mat-sys-outline-variant);
    margin: 0 4px;
    flex-shrink: 0;
    opacity: 0.6;
}

// ─── Workspace Body ───────────────────────────────────────────────────────────
.workspace-body {
    grid-column: 2;
    grid-row: 2;
    display: grid;
    grid-template-columns: auto minmax(0, 1fr);
    min-height: 0;
    min-width: 0;
    overflow: hidden;
    background: var(--app-rail-bg, var(--mat-sys-surface-container-low));

    &.single-pane {
        grid-template-columns: 1fr;
    }
}

.workspace-now-playing {
    grid-column: 2;
    grid-row: 3;
}

// ─── Context Panel ────────────────────────────────────────────────────────────
.context-panel {
    border-right: 1px solid var(--mat-sys-outline-variant);
    background: var(--app-rail-bg, var(--mat-sys-surface-container-low));
    display: flex;
    flex-direction: column;
    gap: 6px;
    padding: 12px;
    width: 300px;
    min-width: 0;
    min-height: 0;
    overflow: hidden;
}

.context-panel--route {
    padding: 12px 10px 10px 12px;
    overflow: visible;
}

.context-panel--sources {
    padding: 12px 10px 10px 12px;
    overflow: visible;
}

.context-panel--route app-workspace-context-panel {
    display: flex;
    flex: 1;
    min-height: 0;
    overflow: hidden;
}

.context-panel--sources app-workspace-sources-filters-panel {
    display: flex;
    flex: 1;
    min-height: 0;
    overflow: hidden;
}

.context-panel__header {
    padding: 6px 6px 12px;
}

.context-panel__title {
    font-size: 1rem;
    font-weight: 600;
    letter-spacing: -0.01em;
}

.context-panel__subtitle {
    margin-top: 2px;
    font-size: 0.78rem;
    color: var(--mat-sys-on-surface-variant);
}

.context-item {
    width: 100%;
    min-height: 36px;
    border: 1px solid transparent;
    border-radius: 8px;
    background: transparent;
    color: var(--mat-sys-on-surface-variant);
    text-align: left;
    padding: 0 10px;
    cursor: pointer;
    font: inherit;
    font-size: 0.875rem;
    transition:
        all 0.15s ease,
        border-color 0.15s ease;

    &:hover {
        border-color: var(--mat-sys-outline-variant);
        color: var(--mat-sys-on-surface);
        background: var(--mat-sys-surface-container);
    }

    &.is-active {
        border-color: var(--app-selection-border);
        color: var(--app-selection-color);
        background: linear-gradient(
            145deg,
            var(--app-selection-surface-strong),
            var(--app-selection-surface)
        );
        box-shadow: 0 10px 20px -18px var(--app-selection-glow);
        font-weight: 500;
    }
}

.context-panel__footer {
    margin-top: auto;
    border-top: 1px solid var(--mat-sys-outline-variant);
    padding: 12px 6px 2px;
    color: var(--mat-sys-on-surface-variant);
    font-size: 0.82rem;

    p {
        margin: 0 0 8px;
        line-height: 1.4;
    }

    a {
        color: var(--mat-sys-primary);
        text-decoration: none;
        font-weight: 600;
    }
}

// ─── Main Content Area ────────────────────────────────────────────────────────
.workspace-content {
    min-width: 0;
    min-height: 0;
    overflow: auto;
    background: var(--app-content-bg, var(--mat-sys-surface));
    // Distinctive top-left inset radius (GitButler-style panel inset)
    border-radius: 16px 0 0 0;
    box-shadow: -4px 8px 20px rgba(0, 0, 0, 0.18);
}

// ─── Dialog Surfaces ──────────────────────────────────────────────────────────
:host ::ng-deep .workspace-command-palette-overlay .mat-mdc-dialog-surface {
    background: transparent;
    box-shadow: none;
    overflow: visible;
}

// ─── Responsive ───────────────────────────────────────────────────────────────
@media (max-width: 960px) {
    .search-field {
        min-width: 120px;
        flex: 1 1 150px;
    }
}

@media (max-width: 780px) {
    .workspace-shell {
        grid-template-columns: 56px 1fr;
        grid-template-rows: 56px 1fr auto;
    }

    .workspace-header {
        padding-inline: 10px;
        gap: 10px;
    }

    .playlist-switcher {
        width: 190px;
    }

    .header-actions {
        gap: 0;
    }
}

@media (max-width: 640px) {
    .workspace-shell {
        grid-template-columns: 1fr;
        grid-template-rows: 52px 56px minmax(0, 1fr) auto;
    }

    .app-rail {
        grid-column: 1;
        grid-row: 1;
        flex-direction: row;
        justify-content: space-between;
        padding: 6px 10px;
        border-right: none;
        border-bottom: 1px solid var(--mat-sys-outline-variant);

        .brand {
            margin-bottom: 0;
        }
    }

    .rail-divider {
        width: 1px;
        height: 24px;
        margin: 0 4px;
    }

    .rail-footer {
        margin-top: 0;
    }

    .workspace-header {
        grid-column: 1;
        grid-row: 2;
    }

    .playlist-switcher {
        width: auto;
        min-width: 140px;
        flex: 1;
    }

    .workspace-body {
        grid-column: 1;
        grid-row: 3;
    }

    .workspace-now-playing {
        grid-column: 1;
        grid-row: 4;
    }
}

