  1→import { DatePipe, DOCUMENT } from '@angular/common';
  2→import {
  3→    Component,
  4→    computed,
  5→    DestroyRef,
  6→    ElementRef,
  7→    effect,
  8→    inject,
  9→    input,
 10→    output,
 11→    signal,
 12→    viewChild,
 13→} from '@angular/core';
 14→import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
 15→import { FormsModule } from '@angular/forms';
 16→import { MatIconButton } from '@angular/material/button';
 17→import { MatRippleModule } from '@angular/material/core';
 18→import { MatIcon } from '@angular/material/icon';
 19→import { MatInputModule } from '@angular/material/input';
 20→import { MatMenu, MatMenuModule, MatMenuTrigger } from '@angular/material/menu';
 21→import { NavigationEnd, Router } from '@angular/router';
 22→import { Store } from '@ngrx/store';
 23→import { TranslatePipe } from '@ngx-translate/core';
 24→import {
 25→    PlaylistActions,
 26→    selectActivePlaylistId,
 27→    selectAllPlaylistsMeta,
 28→    selectPlaylistsLoadingFlag,
 29→} from 'm3u-state';
 30→import { filter } from 'rxjs';
 31→import { PortalStatus, PortalStatusService } from 'services';
 32→import { PlaylistMeta } from 'shared-interfaces';
 33→
 34→type PlaylistRouteProvider = 'playlists' | 'xtreams' | 'stalker';
 35→type PlaylistSectionProvider = PlaylistRouteProvider;
 36→type PlaylistFilterType = 'm3u' | 'stalker' | 'xtream';
 37→
 38→interface PlaylistRouteContext {
 39→    inWorkspace: boolean;
 40→    isWorkspaceDashboard: boolean;
 41→    provider: PlaylistRouteProvider | null;
 42→    playlistId: string | null;
 43→    section: string | null;
 44→}
 45→
 46→const LAST_SECTION_STORAGE_KEY = 'playlist-switcher:last-sections';
 47→const LAST_ACTIVE_PLAYLIST_STORAGE_KEY =
 48→    'playlist-switcher:last-active-playlist-id';
 49→const SEARCH_QUERY_STORAGE_KEY = 'playlist-switcher:search-query';
 50→const PLAYLIST_TYPE_FILTER_STORAGE_KEY = 'playlist-switcher:type-filters';
 51→const DEFAULT_PLAYLIST_TYPE_FILTERS: Record<PlaylistFilterType, boolean> = {
 52→    m3u: true,
 53→    stalker: true,
 54→    xtream: true,
 55→};
 56→interface PlaylistSectionMemory {
 57→    providers: Partial<Record<PlaylistSectionProvider, string>>;
 58→    playlists: Record<
 59→        string,
 60→        {
 61→            provider: PlaylistSectionProvider;
 62→            section: string;
 63→            updatedAt: number;
 64→        }
 65→    >;
 66→}
 67→const XTREAM_SECTIONS = [
 68→    'live',
 69→    'vod',
 70→    'series',
 71→    'favorites',
 72→    'recent',
 73→    'search',
 74→    'recently-added',
 75→    'downloads',
 76→] as const;
 77→const STALKER_SECTIONS = [
 78→    'itv',
 79→    'vod',
 80→    'series',
 81→    'favorites',
 82→    'recent',
 83→    'search',
 84→    'downloads',
 85→] as const;
 86→const M3U_SECTIONS = ['all', 'groups', 'favorites', 'recent'] as const;
 87→
 88→@Component({
 89→    selector: 'app-playlist-switcher',
 90→    templateUrl: './playlist-switcher.component.html',
 91→    styleUrls: ['./playlist-switcher.component.scss'],
 92→    imports: [
 93→        DatePipe,
 94→        FormsModule,
 95→        MatIcon,
 96→        MatIconButton,
 97→        MatInputModule,
 98→        MatMenuModule,
 99→        MatRippleModule,
100→        TranslatePipe,
101→    ],
102→})
103→export class PlaylistSwitcherComponent {
104→    private readonly document = inject(DOCUMENT);
105→    private readonly destroyRef = inject(DestroyRef);
106→    private readonly router = inject(Router);
107→    private readonly store = inject(Store);
108→    private readonly portalStatusService = inject(PortalStatusService);
109→    private focusSearchTimeoutId: ReturnType<typeof setTimeout> | null = null;
110→
111→    /** Current playlist title to display */
112→    readonly currentTitle = input.required<string>();
113→    /** Subtitle to display (e.g., "123 Channels" or "Xtream Code") */
114→    readonly subtitle = input<string>('');
115→    /** Emitted when a different playlist is selected */
116→    readonly playlistSelected = output<string>();
117→
118→    readonly menuTrigger = viewChild.required<MatMenuTrigger>('menuTrigger');
119→    readonly playlistMenu = viewChild.required<MatMenu>('playlistMenu');
120→    readonly triggerElement =
121→        viewChild.required<ElementRef<HTMLElement>>('triggerElement');
122→    readonly searchInput =
123→        viewChild<ElementRef<HTMLInputElement>>('searchInput');
124→
125→    /** Signal for tracking menu open state */
126→    readonly isMenuOpen = signal(false);
127→
128→    /** Search query for filtering playlists */
129→    readonly searchQuery = signal(this.readPersistedSearchQuery());
130→    readonly playlistTypeFilters = signal(this.readPersistedTypeFilters());
131→
132→    /** All playlists from store */
133→    readonly playlists = this.store.selectSignal(selectAllPlaylistsMeta);
134→    readonly allPlaylistsLoaded = this.store.selectSignal(
135→        selectPlaylistsLoadingFlag
136→    );
137→
138→    /** Filtered playlists based on search query, sorted by importDate (newest first) */
139→    readonly filteredPlaylists = computed(() => {
140→        const query = this.searchQuery().toLowerCase().trim();
141→        const filters = this.playlistTypeFilters();
142→        const allPlaylists = this.playlists();
143→        const filteredByType = allPlaylists.filter((playlist) => {
144→            const playlistType = this.getPlaylistFilterType(playlist);
145→            return filters[playlistType];
146→        });
147→        const filtered = query
148→            ? filteredByType.filter(
149→                  (p) =>
150→                      p.title?.toLowerCase().includes(query) ||
151→                      p.filename?.toLowerCase().includes(query)
152→              )
153→            : filteredByType;
154→
155→        return [...filtered].sort(
156→            (a, b) =>
157→                new Date(b.importDate ?? 0).getTime() -
158→                new Date(a.importDate ?? 0).getTime()
159→        );
160→    });
161→
162→    /** Current active playlist ID from route */
163→    readonly routePlaylistId = signal<string | null>(null);
164→    readonly selectedPlaylistId = this.store.selectSignal(
165→        selectActivePlaylistId
166→    );
167→    readonly activePlaylistId = computed(() => {
168→        return this.routePlaylistId() ?? this.selectedPlaylistId() ?? null;
169→    });
170→    readonly activePlaylist = computed(() => {
171→        const playlistId = this.activePlaylistId();
172→        if (!playlistId) {
173→            return null;
174→        }
175→
176→        return (
177→            this.playlists().find((playlist) => playlist._id === playlistId) ??
178→            null
179→        );
180→    });
181→    readonly displayTitle = computed(() => {
182→        if (!this.activePlaylistId()) {
183→            return 'Select playlist';
184→        }
185→
186→        return (
187→            this.currentTitle() ||
188→            this.activePlaylist()?.title ||
189→            this.activePlaylist()?.filename ||
190→            this.activePlaylist()?.url ||
191→            this.activePlaylist()?.portalUrl ||
192→            'Untitled playlist'
193→        );
194→    });
195→
196→    /** Portal statuses for Xtream playlists */
197→    readonly portalStatuses = signal<Map<string, PortalStatus>>(new Map());
198→
199→    constructor() {
200→        // Extract playlist ID from current route
201→        this.updateActivePlaylistFromRoute(this.router.url);
202→        this.rememberSectionFromRoute(this.router.url);
203→        effect(() => {
204→            if (!this.allPlaylistsLoaded()) {
205→                return;
206→            }
207→            const playlistIds = this.playlists().map(
208→                (playlist) => playlist._id
209→            );
210→            this.removeDeletedPlaylistsFromSectionMemory(playlistIds);
211→        });
212→        effect(() => {
213→            const allPlaylistsLoaded = this.allPlaylistsLoaded();
214→            const playlistIds = this.playlists().map(
215→                (playlist) => playlist._id
216→            );
217→            const playlistIdSet = new Set(playlistIds);
218→            const selectedId = this.selectedPlaylistId();
219→            const routeId = this.routePlaylistId();
220→            const storedId = this.readPersistedActivePlaylistId();
221→
222→            // Before playlists are loaded, avoid stale cleanups.
223→            // But still keep storage in sync with explicit runtime context.
224→            if (!allPlaylistsLoaded) {
225→                if (routeId) {
226→                    this.writePersistedActivePlaylistId(routeId);
227→                    return;
228→                }
229→                if (selectedId) {
230→                    this.writePersistedActivePlaylistId(selectedId);
231→                }
232→                return;
233→            }
234→
235→            // If route provides playlist context, keep storage in sync with URL state.
236→            if (routeId && playlistIdSet.has(routeId)) {
237→                this.writePersistedActivePlaylistId(routeId);
238→                return;
239→            }
240→
241→            // Keep storage up-to-date with selected playlist state.
242→            if (selectedId && playlistIdSet.has(selectedId)) {
243→                this.writePersistedActivePlaylistId(selectedId);
244→                return;
245→            }
246→
247→            // On routes without playlist in URL (for example dashboard),
248→            // restore last known active playlist when store has none.
249→            if (
250→                !routeId &&
251→                !selectedId &&
252→                storedId &&
253→                playlistIdSet.has(storedId)
254→            ) {
255→                this.store.dispatch(
256→                    PlaylistActions.setActivePlaylist({ playlistId: storedId })
257→                );
258→                return;
259→            }
260→
261→            // Remove stale value if playlist no longer exists.
262→            if (storedId && !playlistIdSet.has(storedId)) {
263→                this.clearPersistedActivePlaylistId();
264→            }
265→        });
266→
267→        // Listen for route changes
268→        this.router.events
269→            .pipe(
270→                filter((event) => event instanceof NavigationEnd),
271→                takeUntilDestroyed()
272→            )
273→            .subscribe((event: NavigationEnd) => {
274→                this.updateActivePlaylistFromRoute(event.urlAfterRedirects);
275→                this.rememberSectionFromRoute(event.urlAfterRedirects);
276→            });
277→
278→        this.destroyRef.onDestroy(() => {
279→            this.clearMenuOverlayWidth();
280→            this.clearSearchFocusTimeout();
281→        });
282→    }
283→
284→    private updateActivePlaylistFromRoute(url: string) {
285→        // Match routes like /playlists/:id, /xtreams/:id, /stalker/:id
286→        const match = url.match(/\/(playlists|xtreams|stalker)\/([^/?]+)/);
287→        if (match) {
288→            this.routePlaylistId.set(match[2]);
289→        } else {
290→            this.routePlaylistId.set(null);
291→        }
292→    }
293→
294→    private rememberSectionFromRoute(url: string): void {
295→        const routeContext = this.getRouteContext(url);
296→        if (!routeContext.provider || !routeContext.section) {
297→            return;
298→        }
299→
300→        const normalized = this.normalizeSectionForProvider(
301→            routeContext.section,
302→            routeContext.provider
303→        );
304→        if (!normalized) {
305→            return;
306→        }
307→
308→        const memory = this.readSectionMemory();
309→        memory.providers[routeContext.provider] = normalized;
310→        if (routeContext.playlistId) {
311→            memory.playlists[routeContext.playlistId] = {
312→                provider: routeContext.provider,
313→                section: normalized,
314→                updatedAt: Date.now(),
315→            };
316→        }
317→        this.writeSectionMemory(memory);
318→    }
319→
320→    private async checkPortalStatuses(playlists: PlaylistMeta[]) {
321→        const statusPromises = playlists
322→            .filter(
323→                (playlist) =>
324→                    playlist.serverUrl && playlist.username && playlist.password
325→            )
326→            .map(async (playlist) => {
327→                try {
328→                    const status =
329→                        await this.portalStatusService.checkPortalStatus(
330→                            playlist.serverUrl,
331→                            playlist.username,
332→                            playlist.password
333→                        );
334→                    return { id: playlist._id, status };
335→                } catch {
336→                    return {
337→                        id: playlist._id,
338→                        status: 'unavailable' as PortalStatus,
339→                    };
340→                }
341→            });
342→
343→        const results = await Promise.all(statusPromises);
344→        const statusMap = new Map(results.map((r) => [r.id, r.status]));
345→        this.portalStatuses.set(statusMap);
346→    }
347→
348→    onMenuOpened() {
349→        this.isMenuOpen.set(true);
350→        this.syncMenuOverlayWidthToTrigger();
351→        this.focusSearchField();
352→        this.checkPortalStatuses(this.playlists());
353→    }
354→
355→    onMenuClosed() {
356→        this.isMenuOpen.set(false);
357→        this.clearMenuOverlayWidth();
358→        this.clearSearchFocusTimeout();
359→    }
360→
361→    setSearchQuery(value: string) {
362→        this.searchQuery.set(value);
363→        this.writePersistedSearchQuery(value);
364→    }
365→
366→    togglePlaylistTypeFilter(type: PlaylistFilterType, event?: Event): void {
367→        event?.stopPropagation();
368→        const current = this.playlistTypeFilters();
369→        const next = {
370→            ...current,
371→            [type]: !current[type],
372→        };
373→
374→        if (!next.m3u && !next.stalker && !next.xtream) {
375→            return;
376→        }
377→
378→        this.playlistTypeFilters.set(next);
379→        this.writePersistedTypeFilters(next);
380→    }
381→
382→    isTypeFilterSelected(type: PlaylistFilterType): boolean {
383→        return this.playlistTypeFilters()[type];
384→    }
385→
386→    private syncMenuOverlayWidthToTrigger() {
387→        const triggerWidth = Math.round(
388→            this.triggerElement().nativeElement.getBoundingClientRect().width
389→        );
390→        this.document.documentElement.style.setProperty(
391→            '--playlist-switcher-overlay-width',
392→            `${triggerWidth}px`
393→        );
394→    }
395→
396→    private clearMenuOverlayWidth() {
397→        this.document.documentElement.style.removeProperty(
398→            '--playlist-switcher-overlay-width'
399→        );
400→    }
401→
402→    private focusSearchField() {
403→        this.clearSearchFocusTimeout();
404→        this.focusSearchTimeoutId = setTimeout(() => {
405→            const input = this.searchInput()?.nativeElement;
406→            if (!input) {
407→                return;
408→            }
409→            input.focus();
410→            input.select();
411→            this.focusSearchTimeoutId = null;
412→        }, 0);
413→    }
414→
415→    private clearSearchFocusTimeout() {
416→        if (this.focusSearchTimeoutId !== null) {
417→            clearTimeout(this.focusSearchTimeoutId);
418→            this.focusSearchTimeoutId = null;
419→        }
420→    }
421→
422→    selectPlaylist(playlist: PlaylistMeta) {
423→        const routeContext = this.getRouteContext(this.router.url);
424→        const provider = this.getProviderForPlaylist(playlist);
425→
426→        this.setActivePlaylist(playlist._id);
427→
428→        const targetCommands = this.getTargetCommands(
429→            provider,
430→            playlist._id,
431→            routeContext
432→        );
433→        if (targetCommands) {
434→            this.router.navigate(targetCommands);
435→        }
436→
437→        this.playlistSelected.emit(playlist._id);
438→    }
439→
440→    private setActivePlaylist(playlistId: string): void {
441→        this.store.dispatch(PlaylistActions.setActivePlaylist({ playlistId }));
442→    }
443→
444→    private isWorkspaceRoute(url: string): boolean {
445→        return /^\/workspace(?:\/|$)/.test(url);
446→    }
447→
448→    private getProviderForPlaylist(
449→        playlist: PlaylistMeta
450→    ): PlaylistRouteProvider {
451→        if (playlist.serverUrl) {
452→            return 'xtreams';
453→        }
454→        if (playlist.macAddress) {
455→            return 'stalker';
456→        }
457→        return 'playlists';
458→    }
459→
460→    private getPlaylistFilterType(playlist: PlaylistMeta): PlaylistFilterType {
461→        if (playlist.macAddress) {
462→            return 'stalker';
463→        }
464→        if (playlist.serverUrl) {
465→            return 'xtream';
466→        }
467→        return 'm3u';
468→    }
469→
470→    private getRouteContext(url: string): PlaylistRouteContext {
471→        const inWorkspace = this.isWorkspaceRoute(url);
472→        const isWorkspaceDashboard =
473→            /^\/workspace(?:\/dashboard)?(?:\/)?(?:\?.*)?$/.test(url);
474→        const match = url.match(
475→            /^\/(?:workspace\/)?(playlists|xtreams|stalker)\/([^/?]+)(?:\/([^/?]+))?/
476→        );
477→
478→        return {
479→            inWorkspace,
480→            isWorkspaceDashboard,
481→            provider: (match?.[1] as PlaylistRouteProvider | undefined) ?? null,
482→            playlistId: match?.[2] ?? null,
483→            section: match?.[3] ?? null,
484→        };
485→    }
486→
487→    private getTargetCommands(
488→        provider: PlaylistRouteProvider,
489→        playlistId: string,
490→        routeContext: PlaylistRouteContext
491→    ): string[] | null {
492→        const prefix = routeContext.inWorkspace ? ['workspace'] : [];
493→
494→        // In workspace routes without explicit provider context (for example
495→        // dashboard and sources), selecting a source should only change active
496→        // context and must not trigger navigation.
497→        if (routeContext.inWorkspace && !routeContext.provider) {
498→            return null;
499→        }
500→
501→        if (provider === 'playlists') {
502→            const section = this.resolveTargetSection(
503→                provider,
504→                routeContext.section,
505→                playlistId
506→            );
507→            return [...prefix, 'playlists', playlistId, section];
508→        }
509→
510→        if (!this.supportsSectionNavigation(provider)) {
511→            return [...prefix, provider, playlistId];
512→        }
513→
514→        const section = this.resolveTargetSection(
515→            provider,
516→            routeContext.section,
517→            playlistId
518→        );
519→        return [...prefix, provider, playlistId, section];
520→    }
521→
522→    private resolveTargetSection(
523→        provider: PlaylistSectionProvider,
524→        currentSection: string | null,
525→        targetPlaylistId: string
526→    ): string {
527→        const fromCurrent = this.normalizeSectionForProvider(
528→            currentSection,
529→            provider
530→        );
531→        if (fromCurrent) {
532→            return fromCurrent;
533→        }
534→
535→        const memory = this.readSectionMemory();
536→        const playlistMemory = memory.playlists[targetPlaylistId];
537→        if (playlistMemory?.provider === provider) {
538→            const normalizedPlaylistSection = this.normalizeSectionForProvider(
539→                playlistMemory.section,
540→                provider
541→            );
542→            if (normalizedPlaylistSection) {
543→                return normalizedPlaylistSection;
544→            }
545→        }
546→
547→        const providerMemory = memory.providers[provider];
548→        const normalizedProviderSection = this.normalizeSectionForProvider(
549→            providerMemory,
550→            provider
551→        );
552→        if (normalizedProviderSection) {
553→            return normalizedProviderSection;
554→        }
555→
556→        if (provider === 'playlists') {
557→            return 'all';
558→        }
559→
560→        return 'vod';
561→    }
562→
563→    private supportsSectionNavigation(
564→        provider: PlaylistSectionProvider
565→    ): boolean {
566→        if (provider === 'xtreams') {
567→            return Boolean(window.electron);
568→        }
569→        return true;
570→    }
571→
572→    private normalizeSectionForProvider(
573→        section: string | null | undefined,
574→        provider: PlaylistSectionProvider
575→    ): string | null {
576→        if (!section) {
577→            return null;
578→        }
579→
580→        if (provider === 'xtreams') {
581→            if (section === 'itv') {
582→                return 'live';
583→            }
584→            return XTREAM_SECTIONS.includes(
585→                section as (typeof XTREAM_SECTIONS)[number]
586→            )
587→                ? section
588→                : null;
589→        }
590→
591→        if (provider === 'playlists') {
592→            return M3U_SECTIONS.includes(
593→                section as (typeof M3U_SECTIONS)[number]
594→            )
595→                ? section
596→                : null;
597→        }
598→
599→        if (section === 'live') {
600→            return 'itv';
601→        }
602→        if (section === 'recently-added') {
603→            return 'recent';
604→        }
605→        return STALKER_SECTIONS.includes(
606→            section as (typeof STALKER_SECTIONS)[number]
607→        )
608→            ? section
609→            : null;
610→    }
611→
612→    private readSectionMemory(): PlaylistSectionMemory {
613→        const empty: PlaylistSectionMemory = { providers: {}, playlists: {} };
614→
615→        try {
616→            const raw = localStorage.getItem(LAST_SECTION_STORAGE_KEY);
617→            if (!raw) {
618→                return empty;
619→            }
620→            const parsed = JSON.parse(raw);
621→            if (typeof parsed !== 'object' || parsed === null) {
622→                return empty;
623→            }
624→
625→            const providers: Partial<Record<PlaylistSectionProvider, string>> =
626→                {};
627→            const playlists: PlaylistSectionMemory['playlists'] = {};
628→
629→            const parsedProviders = (parsed as Record<string, unknown>)[
630→                'providers'
631→            ];
632→            if (
633→                typeof parsedProviders === 'object' &&
634→                parsedProviders !== null
635→            ) {
636→                const candidate = parsedProviders as Record<string, unknown>;
637→                if (typeof candidate['playlists'] === 'string') {
638→                    providers.playlists = candidate['playlists'];
639→                }
640→                if (typeof candidate['xtreams'] === 'string') {
641→                    providers.xtreams = candidate['xtreams'];
642→                }
643→                if (typeof candidate['stalker'] === 'string') {
644→                    providers.stalker = candidate['stalker'];
645→                }
646→            } else {
647→                // Backward compatibility with previous format:
648→                // { playlists: "...", xtreams: "...", stalker: "..." }
649→                const legacy = parsed as Record<string, unknown>;
650→                if (typeof legacy['playlists'] === 'string') {
651→                    providers.playlists = legacy['playlists'];
652→                }
653→                if (typeof legacy['xtreams'] === 'string') {
654→                    providers.xtreams = legacy['xtreams'];
655→                }
656→                if (typeof legacy['stalker'] === 'string') {
657→                    providers.stalker = legacy['stalker'];
658→                }
659→            }
660→
661→            const parsedPlaylists = (parsed as Record<string, unknown>)[
662→                'playlists'
663→            ];
664→            if (
665→                typeof parsedPlaylists === 'object' &&
666→                parsedPlaylists !== null
667→            ) {
668→                Object.entries(
669→                    parsedPlaylists as Record<string, unknown>
670→                ).forEach(([playlistId, value]) => {
671→                    if (!value || typeof value !== 'object' || !playlistId) {
672→                        return;
673→                    }
674→
675→                    const row = value as Record<string, unknown>;
676→                    const provider = row['provider'];
677→                    const section = row['section'];
678→                    const updatedAt = row['updatedAt'];
679→                    const isProviderValid =
680→                        provider === 'playlists' ||
681→                        provider === 'xtreams' ||
682→                        provider === 'stalker';
683→                    if (!isProviderValid || typeof section !== 'string') {
684→                        return;
685→                    }
686→
687→                    playlists[playlistId] = {
688→                        provider,
689→                        section,
690→                        updatedAt:
691→                            typeof updatedAt === 'number'
692→                                ? updatedAt
693→                                : Date.now(),
694→                    };
695→                });
696→            }
697→
698→            return { providers, playlists };
699→        } catch {
700→            return empty;
701→        }
702→    }
703→
704→    private writeSectionMemory(memory: PlaylistSectionMemory): void {
705→        try {
706→            localStorage.setItem(
707→                LAST_SECTION_STORAGE_KEY,
708→                JSON.stringify(memory)
709→            );
710→        } catch {
711→            // Ignore storage write failures (private mode/storage quota).
712→        }
713→    }
714→
715→    private readPersistedActivePlaylistId(): string | null {
716→        try {
717→            const value = localStorage.getItem(
718→                LAST_ACTIVE_PLAYLIST_STORAGE_KEY
719→            );
720→            return value && value.trim().length > 0 ? value : null;
721→        } catch {
722→            return null;
723→        }
724→    }
725→
726→    private writePersistedActivePlaylistId(playlistId: string): void {
727→        try {
728→            localStorage.setItem(LAST_ACTIVE_PLAYLIST_STORAGE_KEY, playlistId);
729→        } catch {
730→            // Ignore storage write failures (private mode/storage quota).
731→        }
732→    }
733→
734→    private clearPersistedActivePlaylistId(): void {
735→        try {
736→            localStorage.removeItem(LAST_ACTIVE_PLAYLIST_STORAGE_KEY);
737→        } catch {
738→            // Ignore storage write failures.
739→        }
740→    }
741→
742→    private readPersistedSearchQuery(): string {
743→        try {
744→            return localStorage.getItem(SEARCH_QUERY_STORAGE_KEY) ?? '';
745→        } catch {
746→            return '';
747→        }
748→    }
749→
750→    private writePersistedSearchQuery(value: string): void {
751→        try {
752→            localStorage.setItem(SEARCH_QUERY_STORAGE_KEY, value);
753→        } catch {
754→            // Ignore storage write failures (private mode/storage quota).
755→        }
756→    }
757→
758→    private readPersistedTypeFilters(): Record<PlaylistFilterType, boolean> {
759→        try {
760→            const raw = localStorage.getItem(PLAYLIST_TYPE_FILTER_STORAGE_KEY);
761→            if (!raw) {
762→                return { ...DEFAULT_PLAYLIST_TYPE_FILTERS };
763→            }
764→
765→            const parsed = JSON.parse(raw) as Partial<
766→                Record<PlaylistFilterType, boolean>
767→            >;
768→            const next = {
769→                m3u: parsed.m3u !== false,
770→                stalker: parsed.stalker !== false,
771→                xtream: parsed.xtream !== false,
772→            };
773→
774→            if (!next.m3u && !next.stalker && !next.xtream) {
775→                return { ...DEFAULT_PLAYLIST_TYPE_FILTERS };
776→            }
777→
778→            return next;
779→        } catch {
780→            return { ...DEFAULT_PLAYLIST_TYPE_FILTERS };
781→        }
782→    }
783→
784→    private writePersistedTypeFilters(
785→        filters: Record<PlaylistFilterType, boolean>
786→    ): void {
787→        try {
788→            localStorage.setItem(
789→                PLAYLIST_TYPE_FILTER_STORAGE_KEY,
790→                JSON.stringify(filters)
791→            );
792→        } catch {
793→            // Ignore storage write failures (private mode/storage quota).
794→        }
795→    }
796→
797→    private removeDeletedPlaylistsFromSectionMemory(
798→        existingIds: string[]
799→    ): void {
800→        const existingIdSet = new Set(existingIds);
801→        const memory = this.readSectionMemory();
802→        const currentEntries = Object.entries(memory.playlists);
803→        if (currentEntries.length === 0) {
804→            return;
805→        }
806→
807→        const nextPlaylists: PlaylistSectionMemory['playlists'] = {};
808→        let hasChanges = false;
809→
810→        currentEntries.forEach(([playlistId, entry]) => {
811→            if (!existingIdSet.has(playlistId)) {
812→                hasChanges = true;
813→                return;
814→            }
815→
816→            const normalizedSection = this.normalizeSectionForProvider(
817→                entry.section,
818→                entry.provider
819→            );
820→            if (!normalizedSection) {
821→                hasChanges = true;
822→                return;
823→            }
824→
825→            nextPlaylists[playlistId] = {
826→                ...entry,
827→                section: normalizedSection,
828→            };
829→        });
830→
831→        if (!hasChanges) {
832→            return;
833→        }
834→
835→        this.writeSectionMemory({
836→            providers: memory.providers,
837→            playlists: nextPlaylists,
838→        });
839→    }
840→
841→    getPlaylistIcon(playlist: PlaylistMeta): string {
842→        if (playlist.macAddress) {
843→            return 'dashboard';
844→        }
845→        if (playlist.serverUrl) {
846→            return 'public';
847→        }
848→        if (playlist.url) {
849→            return 'cloud';
850→        }
851→        return 'folder';
852→    }
