@use '../../nav-list.scss';

:host {
    display: block;
    width: 100%;
    height: 100%;
    min-height: 0;
}

// ─── Shell Layout ─────────────────────────────────────────────────────────────
.workspace-shell {
    display: grid;
    grid-template-columns: 60px 1fr;
    grid-template-rows: 56px minmax(0, 1fr) auto;
    width: 100%;
    height: 100%;
    min-height: 0;
    overflow: hidden;
    background: var(--app-shell-bg, var(--mat-sys-surface));
    color: var(--mat-sys-on-surface);
}

// ─── App Rail (Sidebar) ───────────────────────────────────────────────────────
.app-rail {
    grid-column: 1;
    grid-row: 1 / span 3;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
    padding: 10px 8px;
    border-right: 1px solid
        var(--app-rail-border, var(--mat-sys-outline-variant));
    background: var(--app-rail-bg, var(--mat-sys-surface-container-low));
    app-region: drag;
    overflow-y: auto;
    overflow-x: hidden;
    scrollbar-width: none;

    &.is-macos {
        padding-top: 36px;
    }

    &::-webkit-scrollbar {
        display: none;
    }
}

.app-rail {
    --rail-link-color: var(--mat-sys-on-surface-variant);
    --rail-link-hover-color: var(--mat-sys-on-surface);
    --rail-link-hover-bg: var(--mat-sys-surface-container);
    --rail-link-active-bg: var(--app-selection-surface);
    --rail-link-active-bg-strong: var(--app-selection-surface-strong);
    --rail-link-active-color: var(--app-selection-color);
    --rail-link-active-icon: var(--app-selection-color);
    --rail-link-active-border: var(--app-selection-border);
    --rail-link-active-glow: var(--app-selection-glow);
}

.app-rail a {
    width: 44px;
    height: 44px;
    border-radius: 14px;
    position: relative;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: var(--rail-link-color);
    text-decoration: none;
    transition:
        background-color 0.2s ease,
        color 0.2s ease,
        box-shadow 0.2s ease,
        transform 0.2s ease;
    app-region: no-drag;

    mat-icon {
        font-size: 20px;
        width: 20px;
        height: 20px;
    }
}

.app-rail a:hover {
    color: var(--rail-link-hover-color);
    background: var(--rail-link-hover-bg);
}

.app-rail a.is-active,
.app-rail a.active {
    color: var(--rail-link-active-color);
    background: linear-gradient(
        145deg,
        var(--rail-link-active-bg-strong),
        var(--rail-link-active-bg)
    );
    box-shadow:
        inset 0 0 0 1px var(--rail-link-active-border),
        0 10px 20px -16px var(--rail-link-active-glow);
    transform: translateY(-1px);

    mat-icon {
        color: var(--rail-link-active-icon);
    }

    &::after {
        content: '';
        position: absolute;
        right: -4px;
        top: 50%;
        transform: translateY(-50%);
        width: 3px;
        height: 18px;
        border-radius: 999px;
        background: var(--rail-link-active-icon);
        box-shadow: 0 0 10px var(--rail-link-active-glow);
    }
}

// ─── Brand Logo ───────────────────────────────────────────────────────────────
.brand {
    margin-bottom: 10px;
    background: var(--mat-sys-primary-container);
    color: var(--mat-sys-on-primary-container);
    width: 40px;
    height: 40px;
    border-radius: 12px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
}

.brand img {
    width: 24px;
    height: 24px;
    object-fit: contain;
}

// ─── Rail Context Region ─────────────────────────────────────────────────────
.rail-context-region {
    --region-accent: var(--mat-sys-outline-variant);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
    width: 52px;
    padding: 6px 4px;
    margin: 4px 0;
    border-radius: 16px;
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.05);
    position: relative;
    animation: region-enter 0.25s ease-out both;

    // Provider accent — top edge glow
    &::before {
        content: '';
        position: absolute;
        top: -1px;
        left: 8px;
        right: 8px;
        height: 2px;
        border-radius: 0 0 2px 2px;
        background: var(--region-accent);
        opacity: 0.6;
    }

    .rail-divider {
        width: 28px;
        margin: 4px 0;
        opacity: 0.3;
    }
}

// Provider accent colors
.rail-context-region--xtreams {
    --region-accent: #7c8cf5;
}

.rail-context-region--stalker {
    --region-accent: #4ecdc4;
}

.rail-context-region--playlists {
    --region-accent: #f5a623;
}

@keyframes region-enter {
    from {
        opacity: 0;
        transform: scale(0.95);
    }
    to {
        opacity: 1;
        transform: scale(1);
    }
}

// ─── Rail Divider ─────────────────────────────────────────────────────────────
.rail-divider {
    width: 44px;
    height: 1px;
    background: var(--mat-sys-outline-variant);
    margin: 6px 0;
    opacity: 0.5;
}

.rail-footer {
    margin-top: auto;

    .rail-shortcut {
        width: 44px;
        height: 44px;
        padding: 0;
        gap: 0;
        border-radius: 14px;
        position: relative;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        color: var(--mat-sys-on-surface-variant);
        app-region: no-drag;

        mat-icon {
            font-size: 20px;
            width: 20px;
            height: 20px;
        }

        &:hover:not(.is-active) {
            background: var(--app-selection-surface);
            color: var(--mat-sys-on-surface);
        }

        &.is-active::after {
            content: '';
            position: absolute;
            right: -4px;
            top: 50%;
            transform: translateY(-50%);
            width: 4px;
            height: 20px;
            border-radius: 999px;
            background: var(--app-selection-color);
            box-shadow: 0 0 10px var(--app-selection-glow);
        }
    }
}

// ─── Workspace Header ─────────────────────────────────────────────────────────
.workspace-header {
    grid-column: 2;
    grid-row: 1;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 0 24px;
    height: 56px;
    border-bottom: 1px solid var(--mat-sys-outline-variant);
    background: var(--app-header-bg, var(--mat-sys-surface-container-low));
    app-region: drag;
}

.playlist-switcher {
    width: min(260px, 32vw);
    flex-shrink: 0;
    app-region: no-drag;
}

.settings-header-title {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: var(--mat-sys-on-surface);
    app-region: no-drag;
}

// ─── Search Field ─────────────────────────────────────────────────────────────
.search-field {
    flex: 1;
    min-width: 160px;
    height: 36px;
    border-radius: 10px;
    border: 1px solid var(--app-search-border, var(--mat-sys-outline-variant));
    background: var(--app-search-bg, var(--mat-sys-surface-container));
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 0 12px;
    transition:
        border-color 0.15s ease,
        background-color 0.15s ease,
        box-shadow 0.15s ease;
    app-region: no-drag;

    &:focus-within {
        border-color: var(--mat-sys-primary);
        box-shadow: 0 0 0 3px color-mix(in srgb, var(--mat-sys-primary) 12%, transparent);
    }

    mat-icon {
        font-size: 18px;
        width: 18px;
        height: 18px;
        color: var(--mat-sys-on-surface-variant);
        flex-shrink: 0;
    }

    input {
        flex: 1;
        border: none;
        outline: none;
        background: transparent;
        color: var(--mat-sys-on-surface);
        font: inherit;
        font-size: 0.875rem;

        &:disabled {
            cursor: not-allowed;
            opacity: 0.5;
        }

        &::placeholder {
            color: var(--mat-sys-on-surface-variant);
            opacity: 0.7;
        }
    }

    .command-trigger {
        width: 28px;
        height: 28px;
        padding: 0;
        margin-right: -4px;
        color: var(--mat-sys-on-surface-variant);
        border-radius: 8px;
        flex-shrink: 0;

        &:hover {
            background: var(--mat-sys-surface-container-high);
            color: var(--mat-sys-on-surface);
        }

        mat-icon {
            font-size: 16px;
            width: 16px;
            height: 16px;
        }
    }
}

// ─── Header Actions ───────────────────────────────────────────────────────────
.header-actions {
    display: flex;
    align-items: center;
    gap: 4px;
    app-region: no-drag;

    button,
    a {
        color: var(--mat-sys-on-surface-variant);
        border-radius: 8px;
        transition:
            color 0.15s ease,
            background 0.15s ease;

        &:hover {
            color: var(--mat-sys-on-surface);
            background: var(--mat-sys-surface-container);
        }

        &.is-active {
            color: var(--app-selection-color);
            background: linear-gradient(
                145deg,
                var(--app-selection-surface-strong),
                var(--app-selection-surface)
            );
            box-shadow:
                inset 0 0 0 1px var(--app-selection-border),
                0 10px 20px -16px var(--app-selection-glow);
        }
    }
}

.header-shortcut--global {
    position: relative;

    &::before {
        content: '';
        position: absolute;
        bottom: 5px;
        right: 5px;
        width: 7px;
        height: 7px;
        border-radius: 50%;
        background: var(--mat-sys-tertiary);
        border: 1.5px solid
            var(--app-header-bg, var(--mat-sys-surface-container-low));
        z-index: 1;
    }
}

.header-actions-divider {
    width: 1px;
    height: 20px;
    background: var(--mat-sys-outline-variant);
    margin: 0 4px;
    flex-shrink: 0;
    opacity: 0.6;
}

// ─── Workspace Body ───────────────────────────────────────────────────────────
.workspace-body {
    grid-column: 2;
    grid-row: 2;
    display: grid;
    grid-template-columns: auto minmax(0, 1fr);
    min-height: 0;
    min-width: 0;
    overflow: hidden;
    background: var(--app-rail-bg, var(--mat-sys-surface-container-low));

    &.single-pane {
        grid-template-columns: 1fr;
    }
}

.workspace-now-playing {
    grid-column: 2;
    grid-row: 3;
}

// ─── Context Panel ────────────────────────────────────────────────────────────
.context-panel {
    border-right: 1px solid var(--mat-sys-outline-variant);
    background: var(--app-rail-bg, var(--mat-sys-surface-container-low));
    display: flex;
    flex-direction: column;
    gap: 6px;
    padding: 12px;
    width: 300px;
    min-width: 0;
    min-height: 0;
    overflow: hidden;
}

.context-panel--route {
    padding: 12px 10px 10px 12px;
    overflow: visible;
}

.context-panel--sources {
    padding: 12px 10px 10px 12px;
    overflow: visible;
}

.context-panel--route app-workspace-context-panel {
    display: flex;
    flex: 1;
    min-height: 0;
    overflow: hidden;
}

.context-panel--sources app-workspace-sources-filters-panel {
    display: flex;
    flex: 1;
    min-height: 0;
    overflow: hidden;
}

.context-panel__header {
    padding: 6px 6px 12px;
}

.context-panel__title {
    font-size: 1rem;
    font-weight: 600;
    letter-spacing: -0.01em;
}

.context-panel__subtitle {
    margin-top: 2px;
    font-size: 0.78rem;
    color: var(--mat-sys-on-surface-variant);
}

.context-item {
    width: 100%;
    min-height: 36px;
    border: 1px solid transparent;
    border-radius: 8px;
    background: transparent;
    color: var(--mat-sys-on-surface-variant);
    text-align: left;
    padding: 0 10px;
    cursor: pointer;
    font: inherit;
    font-size: 0.875rem;
    transition:
        all 0.15s ease,
        border-color 0.15s ease;

    &:hover {
        border-color: var(--mat-sys-outline-variant);
        color: var(--mat-sys-on-surface);
        background: var(--mat-sys-surface-container);
    }

    &.is-active {
        border-color: var(--app-selection-border);
        color: var(--app-selection-color);
        background: linear-gradient(
            145deg,
            var(--app-selection-surface-strong),
            var(--app-selection-surface)
        );
        box-shadow: 0 10px 20px -18px var(--app-selection-glow);
        font-weight: 500;
    }
}

.context-panel__footer {
    margin-top: auto;
    border-top: 1px solid var(--mat-sys-outline-variant);
    padding: 12px 6px 2px;
    color: var(--mat-sys-on-surface-variant);
    font-size: 0.82rem;

    p {
        margin: 0 0 8px;
        line-height: 1.4;
    }

    a {
        color: var(--mat-sys-primary);
        text-decoration: none;
        font-weight: 600;
    }
}

// ─── Main Content Area ────────────────────────────────────────────────────────
.workspace-content {
    min-width: 0;
    min-height: 0;
    overflow: auto;
    background: var(--app-content-bg, var(--mat-sys-surface));
    // Distinctive top-left inset radius (GitButler-style panel inset)
    border-radius: 16px 0 0 0;
    box-shadow: -4px 8px 20px rgba(0, 0, 0, 0.18);
}

// ─── Dialog Surfaces ──────────────────────────────────────────────────────────
:host ::ng-deep .workspace-command-palette-overlay .mat-mdc-dialog-surface {
    background: transparent;
    box-shadow: none;
    overflow: visible;
}

// ─── Responsive ───────────────────────────────────────────────────────────────
@media (max-width: 960px) {
    .search-field {
        min-width: 120px;
        flex: 1 1 150px;
    }
}

@media (max-width: 780px) {
    .workspace-shell {
        grid-template-columns: 56px 1fr;
        grid-template-rows: 56px 1fr auto;
    }

    .workspace-header {
        padding-inline: 10px;
        gap: 10px;
    }

    .playlist-switcher {
        width: 190px;
    }

    .header-actions {
        gap: 0;
    }
}

@media (max-width: 640px) {
    .workspace-shell {
        grid-template-columns: 1fr;
        grid-template-rows: 52px 56px minmax(0, 1fr) auto;
    }

    .app-rail {
        grid-column: 1;
        grid-row: 1;
        flex-direction: row;
        justify-content: space-between;
        padding: 6px 10px;
        border-right: none;
        border-bottom: 1px solid var(--mat-sys-outline-variant);

        .brand {
            margin-bottom: 0;
        }
    }

    .rail-divider {
        width: 1px;
        height: 24px;
        margin: 0 4px;
    }

    .rail-context-region {
        width: auto;
        flex-direction: row;
        margin: 0;
        padding: 2px 4px;
        border-radius: 10px;

        &::before {
            display: none;
        }

        .rail-divider {
            width: 1px;
            height: 24px;
            margin: 0 2px;
        }
    }

    .rail-footer {
        margin-top: 0;
    }

    .workspace-header {
        grid-column: 1;
        grid-row: 2;
    }

    .playlist-switcher {
        width: auto;
        min-width: 140px;
        flex: 1;
    }

    .workspace-body {
        grid-column: 1;
        grid-row: 3;
    }

    .workspace-now-playing {
        grid-column: 1;
        grid-row: 4;
    }
}

